import React from 'react';
import { Link } from 'react-router-dom';
import { AppBar, Toolbar, Button, Box } from '@mui/material';

const Navbar = () => {
  const handleDownloadClick = () => {
    window.open('https://huggingface.co/hyonbokan/BGPStream13-10k-cutoff-1024-max-2048', '_blank');
  };

  // Inline sx prop styles for the links
  const linkStyle = {
    color: 'inherit',
    textDecoration: 'none',
    padding: '8px 8px',
    margin: '0',
    '&:hover': {
      textDecoration: 'underline',
      backgroundColor: 'transparent',
    },
    // Add horizontal margin except for the last item
    '&:not(:last-child)': {
      marginRight: 2, // Adjust this value as needed for more or less space
    }
  };

  return (
    <AppBar position="static" sx={{ backgroundColor: '#2D3748', color: 'white' }}>
      <Toolbar sx={{ justifyContent: 'flex-start' }}>
        <Box sx={{ display: 'flex', alignItems: 'left', marginRight: 'auto' }}>
          <Link to="/" sx={linkStyle}>Home</Link>
        </Box>
        <Box sx={{ display: 'flex', alignItems: 'left', marginRight: 'auto' }}>
          <Link to="/dataset" sx={linkStyle}>Dataset</Link>
        </Box>
        <Box sx={{ display: 'flex', alignItems: 'left', marginRight: 'auto' }}>
          <Link to="/bgp_llama" sx={linkStyle}>BGP-LLaMA</Link>
        </Box>
        <Button color="primary" variant="contained" onClick={handleDownloadClick}>
          Download models
        </Button>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
